options.customCss:
:root {
  /* ─── Growth AI Brand Colors ─── */
  --chat--color-primary: #00C48C;
  --chat--color-primary-shade-50: #00B07D;
  --chat--color-primary-shade-100: #009B6E;
  --chat--color-secondary: #0A0F1E;
  --chat--color-secondary-shade-50: #111827;
  --chat--color-white: #ffffff;
  --chat--color-light: #F0F4F8;
  --chat--color-light-shade-50: #DDE3EC;
  --chat--color-light-shade-100: #B8C3D4;
  --chat--color-medium: #8896AB;
  --chat--color-dark: #0A0F1E;
  --chat--color-disabled: #C8D2DF;
  --chat--color-typing: #404040;

  /* ─── Base Layout ─── */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.25rem;
  --chat--transition-duration: 0.15s;

  /* ─── Police système native (d'origine) ─── */
  --chat--font-family: (
    -apple-system,
    BlinkMacSystemFont,
    'Segoe UI',
    Roboto,
    Oxygen-Sans,
    Ubuntu,
    Cantarell,
    'Helvetica Neue',
    sans-serif
  );

  /* ─── Window Dimensions ─── */
  --chat--window--width: 400px;
  --chat--window--height: 600px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid rgba(0, 196, 140, 0.2);
  --chat--window--border-radius: var(--chat--border-radius);
  --chat--window--margin-bottom: var(--chat--spacing);

  /* ─── Header ─── */
  --chat--header-height: auto;
  --chat--header--padding: var(--chat--spacing);
  --chat--header--background: #0A0F1E;
  --chat--header--color: var(--chat--color-light);
  --chat--header--border-top: none;
  --chat--header--border-bottom: 1px solid rgba(0, 196, 140, 0.25);
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 2em;
  --chat--subtitle--font-size: inherit;
  --chat--subtitle--line-height: 1.8;

  /* ─── Messages ─── */
  --chat--message--font-size: 1rem;
  --chat--message--padding: var(--chat--spacing);
  --chat--message--border-radius: var(--chat--border-radius);
  --chat--message-line-height: 1.5;
  --chat--message--margin-bottom: calc(var(--chat--spacing) * 1);

  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--bot--border: none;

  --chat--message--user--background: #00C48C;
  --chat--message--user--color: var(--chat--color-white);
  --chat--message--user--border: none;

  --chat--message--pre--background: rgba(0, 0, 0, 0.05);
  --chat--messages-list--padding: var(--chat--spacing);

  /* ─── Toggle Button ─── */
  --chat--toggle--size: 64px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: #00C48C;
  --chat--toggle--hover--background: #00B07D;
  --chat--toggle--active--background: #009B6E;
  --chat--toggle--color: var(--chat--color-white);

  /* ─── Input Area ─── */
  --chat--textarea--height: 50px;
  --chat--textarea--max-height: 30rem;
  --chat--input--font-size: inherit;
  --chat--input--border: 0;
  --chat--input--border-radius: 0;
  --chat--input--padding: 0.8rem;
  --chat--input--background: var(--chat--color-white);
  --chat--input--text-color: initial;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: var(--chat--input--font-size);
  --chat--input--border-active: 0;
  --chat--input--left--panel--width: 2rem;

  /* ─── Buttons ─── */
  --chat--button--color: var(--chat--color-light);
  --chat--button--background: #00C48C;
  --chat--button--padding: calc(var(--chat--spacing) * 1 / 2) var(--chat--spacing);
  --chat--button--border-radius: var(--chat--border-radius);
  --chat--button--hover--color: var(--chat--color-light);
  --chat--button--hover--background: #00B07D;
  --chat--close--button--color-hover: #00C48C;

  /* ─── Send & File Buttons ─── */
  --chat--input--send--button--background: var(--chat--color-white);
  --chat--input--send--button--color: #00C48C;
  --chat--input--send--button--background-hover: #00B07D;
  --chat--input--send--button--color-hover: #009B6E;
  --chat--input--file--button--background: var(--chat--color-white);
  --chat--input--file--button--color: #00C48C;
  --chat--input--file--button--background-hover: var(--chat--input--file--button--background);
  --chat--input--file--button--color-hover: #009B6E;
  --chat--files-spacing: 0.25rem;

  /* ─── Body & Footer ─── */
  --chat--body--background: var(--chat--color-light);
  --chat--footer--background: var(--chat--color-light);
  --chat--footer--color: var(--chat--color-dark);
}


/* ══════════════════════════════════════════
   OVERRIDES — Personnalisation Growth AI
══════════════════════════════════════════ */

/* ── Largeur des bulles (identique à l'original) ── */
.chat-message {
  max-width: 50%;
}

/* ── Fenêtre : ombre élégante ── */
.chat-window {
  box-shadow:
    0 20px 60px rgba(10, 15, 30, 0.2),
    0 0 0 1px rgba(0, 196, 140, 0.12) !important;
  overflow: hidden;
}

/* ── Header : dégradé noir → doré Growth AI ── */
.chat-header {
  background: linear-gradient(135deg, #0A0F1E 0%, #1A1408 40%, #B8860B 80%, #D4A017 100%) !important;
  border-bottom: 1px solid rgba(212, 160, 23, 0.4) !important;
  position: relative;
}

/* Trait doré en bas du header */
.chat-header::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 56px;
  height: 2px;
  background: linear-gradient(90deg, #D4A017, #F5C842);
  border-radius: 0 2px 2px 0;
}

/* ── Sous-titre header plus discret ── */
.chat-header p,
.chat-header .chat-subtitle {
  color: rgba(255, 255, 255, 0.5) !important;
}

/* ── Zone messages ── */
.chat-messages-list {
  background: linear-gradient(180deg, #F0F4F8 0%, #EDF1F7 100%) !important;
}

/* ── Bulle bot : bordure verte subtile ── */
.chat-message.chat-message-from-bot .chat-message-bubble {
  border: 1px solid rgba(0, 196, 140, 0.18) !important;
  box-shadow: 0 1px 6px rgba(10, 15, 30, 0.07);
}

/* ── Bulle user : dégradé vert ── */
.chat-message.chat-message-from-user .chat-message-bubble {
  background: linear-gradient(135deg, #00C48C 0%, #00A87A 100%) !important;
  box-shadow: 0 2px 12px rgba(0, 196, 140, 0.35);
}

/* ── Zone de saisie ── */
.chat-input-area,
.chat-inputs-container {
  border-top: 1.5px solid var(--chat--color-light-shade-50) !important;
  background: #ffffff !important;
}

/* ── Placeholder discret ── */
.chat-input::placeholder {
  color: var(--chat--color-light-shade-100) !important;
}

/* ── Bouton send : micro-animation au hover ── */
.chat-input-send-button {
  transition: transform 0.15s ease, color 0.15s ease !important;
}

.chat-input-send-button:hover {
  transform: scale(1.15) rotate(-8deg) !important;
}

/* ── Bouton toggle flottant : halo vert ── */
.chat-window-toggle {
  box-shadow:
    0 4px 20px rgba(0, 196, 140, 0.5),
    0 0 0 3px rgba(0, 196, 140, 0.1) !important;
  transition: box-shadow 0.2s ease, transform 0.2s ease !important;
}

.chat-window-toggle:hover {
  box-shadow:
    0 8px 32px rgba(0, 196, 140, 0.65),
    0 0 0 5px rgba(0, 196, 140, 0.15) !important;
  transform: scale(1.07) !important;
}

/* ── Footer ── */
.chat-footer {
  border-top: 1px solid var(--chat--color-light-shade-50) !important;
}

/* ── Scrollbar custom (Webkit) ── */
.chat-messages-list::-webkit-scrollbar {
  width: 4px;
}

.chat-messages-list::-webkit-scrollbar-track {
  background: transparent;
}

.chat-messages-list::-webkit-scrollbar-thumb {
  background: rgba(0, 196, 140, 0.3);
  border-radius: 4px;
}

.chat-messages-list::-webkit-scrollbar-thumb:hover {
  background: rgba(0, 196, 140, 0.55);
}
